// 1. Obtenemos todos los items de entrada
const items = $input.all();

// 2. Tomamos el nodo correcto (el que realmente existe)
const triggerData = $('When chat message received').first();

// 3. Leemos el binary del trigger
const binaryData = triggerData.binary;

// 4. Comprobamos si hay archivo
if (binaryData && Object.keys(binaryData).length > 0) {
  items[0].binary = binaryData;
  items[0].json.hasPDF = true;
} else {
  items[0].json.hasPDF = false;
}

// 5. Devolvemos los items
return items;

